// Lấy chuỗi text từ kết quả trả về của mô hình Gemini ở node trước
// Đường dẫn này dựa trên cấu trúc chuẩn của Gemini API
let rawText = $input.item.json.candidates[0].content.parts[0].text;

// 1. Xóa bỏ ```json ở đầu và ``` ở cuối
// 2. Dùng trim() để xóa các khoảng trắng hoặc dấu xuống dòng thừa
let cleanText = rawText.replace(/```json/g, "").replace(/```/g, "").trim();

// Chuyển đổi chuỗi text đã làm sạch thành một đối tượng JSON thực sự
let parsedData = JSON.parse(cleanText);

// Trả về kết quả để các node sau (như Webhook Response) có thể sử dụng trực tiếp
return parsedData;

const ngay_thang = $input.first().json.body.ngay_thang;
const tieu_de = $input.first().json.body.tieu_de;
const noi_dung = $input.first().json.body.noi_dung;

const prompt = `Từ đoạn nhật ký sau, hãy trích xuất thông tin và trả về JSON theo schema.

Đoạn nhật ký:
- Ngày tháng: ${ngay_thang}
- Tiêu đề: ${tieu_de}
- Nội dung: ${noi_dung}

YÊU CẦU:
1. Đọc kỹ nội dung nhật ký
2. Trích xuất thông tin thực tế
3. Điền vào JSON (KHÔNG ĐỂ TRỐNG):
{
  "ngay_thang": "DD/MM/YYYY",
  "tieu_de": null hoặc text,
  "cam_xuc_chinh": [list tối đa 3],
  "nguyen_nhan_cot_loi": "30-40 từ",
  "goi_y_chanh_niem": "30-40 từ"
}
Chỉ trả về JSON thuần.`;

return [{
  json: {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: {
      temperature: 0.7,
      topK: 40,
      topP: 0.95,
      response_mime_type: "application/json"
    }
  }
}];
